code = """import pandas as pd
import re
import json

# Access the full dictionary output of the previous query_db call
full_db_response = locals()['var_function-call-7025255247730458322']

# The actual query results are nested under 'query_db_response' and then 'results'
# The 'results' key holds a list, and the actual data (JSON string) is the first element of that list.
raw_result_string = full_db_response['query_db_response']['results'][0]

# Use regex to extract just the JSON array part from the string
# This regex looks for a string starting with '[' and ending with ']' and captures everything in between
json_array_match = re.search(r'\[.*\]', raw_result_string, re.DOTALL)

if json_array_match:
    json_array_str = json_array_match.group(0)
    business_data = json.loads(json_array_str)

    df_business = pd.DataFrame(business_data)

    # Function to extract the state abbreviation from the description
    def extract_state(description):
        if isinstance(description, str):
            # Regex to find a two-letter uppercase abbreviation after ', '
            match = re.search(r',\s*([A-Z]{2})(?:\s|$|,)', description)
            if match:
                return match.group(1)
        return None

    # Apply the function to create a new 'state' column
    df_business['state'] = df_business['description'].apply(extract_state)

    # Filter out businesses where state could not be extracted (e.g., non-U.S. locations or malformed descriptions)
    df_business_wifi = df_business.dropna(subset=['state'])

    # Prepare business_id for joining with review table by replacing prefix
    df_business_wifi['business_ref'] = df_business_wifi['business_id'].str.replace('businessid_', 'businessref_')

    # Select only relevant columns for the next step
    df_final_business_data = df_business_wifi[['business_ref', 'state']].copy()

    print("__RESULT__:")
    print(df_final_business_data.to_json(orient='records'))
else:
    print("__RESULT__:")
    print(json.dumps({"error": "Could not extract JSON array from the string. Raw output: " + raw_result_string}))"""

